const solc = require('solc');

function compile(source, contractName) {
  const input = {
    language: 'Solidity',
    sources: { 'contract.sol': { content: source } },
    settings: { outputSelection: { '*': { '*': ['abi', 'evm.bytecode'] } } }
  };
  const output = JSON.parse(solc.compile(JSON.stringify(input)));
  if (output.errors?.some(e => e.severity === 'error')) {
    throw new Error(output.errors.map(e => e.message).join('\n'));
  }
  const contract = output.contracts['contract.sol'][contractName];
  return {
    abi: contract.abi,
    bytecode: contract.evm.bytecode.object
  };
}

module.exports = { compile };

const { ethers } = require('ethers');

async function deploy({ rpcUrl, privateKey, abi, bytecode, constructorArgs = [], value = '0' }) {
  const provider = new ethers.JsonRpcProvider(rpcUrl);
  const wallet = new ethers.Wallet(privateKey, provider);
  const factory = new ethers.ContractFactory(abi, bytecode, wallet);

  const contract = await factory.deploy(...constructorArgs, {
    value: ethers.parseEther(value)
  });

  const receipt = await contract.deploymentTransaction().wait();

  return {
    address: await contract.getAddress(),
    tx_hash: receipt.hash,
    block_number: receipt.blockNumber,
    gas_used: receipt.gasUsed.toString(),
    abi
  };
}

module.exports = { deploy };

const { ethers } = require('ethers');

async function deployCreate2({ rpcUrl, privateKey, bytecode, salt, factoryAddress }) {
  const provider = new ethers.JsonRpcProvider(rpcUrl);
  const wallet = new ethers.Wallet(privateKey, provider);

  // Compute deterministic address
  const initCodeHash = ethers.keccak256(bytecode);
  const predicted = ethers.getCreate2Address(factoryAddress, salt, initCodeHash);

  // Deploy via factory
  const factory = new ethers.Contract(factoryAddress, [
    'function deploy(bytes32 salt, bytes calldata bytecode) returns (address)'
  ], wallet);

  const tx = await factory.deploy(salt, bytecode);
  const receipt = await tx.wait();

  return { address: predicted, tx_hash: receipt.hash };
}

module.exports = { deployCreate2 };
